import React from 'react';

const Home = ({ onSellClick, onBuyClick }) => {
  return (
    <div className="min-h-screen bg-gradient-to-b from-green-50 to-green-200 flex flex-col items-center p-6">
      {/* Header Area */}
      <div className="w-full max-w-md flex justify-between items-center mb-10 mt-4">
        <h1 className="text-3xl font-black text-green-800 tracking-tighter">KisanMarket</h1>
        <div className="bg-white px-4 py-2 rounded-full shadow-sm border border-green-200 font-bold text-green-700">
          🇮🇳 English
        </div>
      </div>

      {/* Main Action Buttons */}
      <div className="w-full max-w-md space-y-6">
        
        {/* SELL BUTTON */}
        <button 
          onClick={onSellClick}
          className="w-full bg-green-600 hover:bg-green-700 active:scale-95 transition-all py-10 rounded-[35px] shadow-[0_10px_0_0_#1a3a16] flex flex-col items-center justify-center group"
        >
          <span className="text-6xl mb-2">🚜</span>
          <span className="text-white text-4xl font-black uppercase">Sell Crops</span>
          <span className="text-green-100 font-medium">पीक विका / फसल बेचें</span>
        </button>

        {/* BUY BUTTON */}
        <button 
          onClick={onBuyClick}
          className="w-full bg-orange-500 hover:bg-orange-600 active:scale-95 transition-all py-10 rounded-[35px] shadow-[0_10px_0_0_#9a3412] flex flex-col items-center justify-center"
        >
          <span className="text-6xl mb-2">🛒</span>
          <span className="text-white text-4xl font-black uppercase">Buy Crops</span>
          <span className="text-orange-100 font-medium">खरेदी करा / खरीदें</span>
        </button>

      </div>

      {/* VOICE ASSISTANT FOOTER */}
      <div className="mt-auto mb-10 flex flex-col items-center">
        <button className="w-24 h-24 bg-blue-500 rounded-full flex items-center justify-center text-4xl shadow-xl border-8 border-white animate-bounce">
          🎤
        </button>
        <p className="mt-4 text-blue-700 font-black text-xl uppercase tracking-widest text-center">
          Speak to Assistant<br/>(बोला / बोलिए)
        </p>
      </div>
    </div>
  );
};

export default Home;
